UPDATE J09A_temp
SET ENTSCHEIDUNG = CASE WHEN HAUS IN (
    SELECT HAUS FROM (
        SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
        FROM J09A_temp
        GROUP BY HAUS
    )
    WHERE eq_count < 3
) THEN 'KSA' ELSE 'EVU' END;

UPDATE J09A_temp
SET ENTSCHEIDUNG = CASE WHEN HAUS IN (
    SELECT HAUS FROM (
        SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
        FROM J09A_temp
        GROUP BY HAUS
    )
    WHERE eq_count < 3
) THEN 'KSA' ELSE 'EVU' END;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 = 0;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 500 AND 599;

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HOUSE_NUM1 BETWEEN 900 AND 999;
